import{_ as e,W as i,X as t,Y as a,Z as l,a0 as d,$ as s,E as c}from"./framework-586fce15.js";const r="/learn_linux/assets/1664849831679287-91d174d9.png",o="/learn_linux/assets/16648498319128447-64c7540a.png",p="/learn_linux/assets/1664849832160575-cb3db5dd.png",u="/learn_linux/assets/16648498324312801-2fb6c397.png",g="/learn_linux/assets/16648498327265737-422aa1c5.png",m="/learn_linux/assets/16648498330310729-3ff36b47.png",h="/learn_linux/assets/16648498334588249-166badcc.png",b="/learn_linux/assets/16648498338327637-38465ec1.png",v="/learn_linux/assets/166484983399699-da6876aa.png",f="/learn_linux/assets/1664849834114752-932a48fd.png",k={},_=s(`<ul><li><a href="#1-basic">1. basic</a><ul><li><a href="#11-%E5%AE%89%E8%A3%85">1.1. 安装</a></li><li><a href="#12-%E6%9C%AC%E5%9C%B0%E6%8F%90%E4%BA%A4">1.2. 本地提交</a><ul><li><a href="#121-git-init">1.2.1. git init</a></li><li><a href="#122-%E6%9F%A5%E7%9C%8B%E5%B7%A5%E4%BD%9C%E5%8C%BA%E7%9A%84%E6%96%87%E4%BB%B6">1.2.2. 查看工作区的文件</a></li><li><a href="#123-add%E5%88%B0%E6%9A%82%E5%AD%98%E5%8C%BA">1.2.3. add到暂存区</a></li><li><a href="#124-commit%E5%88%B0%E6%9C%AC%E5%9C%B0%E4%BB%93%E5%BA%93">1.2.4. commit到本地仓库</a></li><li><a href="#125-%E5%88%A0%E9%99%A4%E6%96%87%E4%BB%B6">1.2.5. 删除文件</a></li></ul></li><li><a href="#13-%E8%BF%9C%E7%A8%8B%E4%BB%93%E5%BA%93">1.3. 远程仓库</a><ul><li><a href="#131-github--git">1.3.1. github &amp; git</a><ul><li><a href="#1311-git-config">1.3.1.1. git config</a></li><li><a href="#1312-ssh">1.3.1.2. ssh</a></li></ul></li><li><a href="#132-%E5%B0%86%E6%9C%AC%E5%9C%B0%E5%86%99%E5%A5%BD%E7%9A%84%E4%B8%9C%E8%A5%BF%E6%8F%90%E4%BA%A4%E5%88%B0%E7%A9%BA%E7%9A%84%E8%BF%9C%E7%A8%8B%E4%BB%93%E5%BA%93">1.3.2. 将本地写好的东西提交到空的远程仓库</a></li><li><a href="#133-%E5%B0%86%E6%9C%AC%E5%9C%B0%E5%86%99%E5%A5%BD%E7%9A%84%E4%B8%9C%E8%A5%BF%E6%8F%90%E4%BA%A4%E5%88%B0%E6%9C%89%E4%B8%9C%E8%A5%BF%E7%9A%84%E8%BF%9C%E7%A8%8B%E4%BB%93%E5%BA%93">1.3.3. 将本地写好的东西提交到有东西的远程仓库</a></li></ul></li></ul></li></ul><hr><h1 id="_1-basic" tabindex="-1"><a class="header-anchor" href="#_1-basic" aria-hidden="true">#</a> 1. basic</h1><h2 id="_1-1-安装" tabindex="-1"><a class="header-anchor" href="#_1-1-安装" aria-hidden="true">#</a> 1.1. 安装</h2><p>linux：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> <span class="token function">git</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>windows:</p>`,7),x={href:"https://registry.npmmirror.com/binary.html?path=git-for-windows/",target:"_blank",rel:"noopener noreferrer"},E=s('<p><img src="'+r+`" alt="1664849831679287.png"></p><h2 id="_1-2-本地提交" tabindex="-1"><a class="header-anchor" href="#_1-2-本地提交" aria-hidden="true">#</a> 1.2. 本地提交</h2><h3 id="_1-2-1-git-init" tabindex="-1"><a class="header-anchor" href="#_1-2-1-git-init" aria-hidden="true">#</a> 1.2.1. git init</h3><p>怎么让这个普通的文件夹，变成git的仓库呢？ 用这个命令生成一个 <code>.git</code>配置来允许git来管理它，所有 Git 需要的数据和资源都存放在这个目录中。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> init
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>你会发现在文件夹下面多里一个名为<code>.git</code>的文件夹。</p><p><img src="`+o+`" alt="16648498319128447.png"></p><h3 id="_1-2-2-查看工作区的文件" tabindex="-1"><a class="header-anchor" href="#_1-2-2-查看工作区的文件" aria-hidden="true">#</a> 1.2.2. 查看工作区的文件</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> status

Untracked files:

Changes not staged <span class="token keyword">for</span> commit:
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这条命令显示还没有提交到缓存区的工作区的文件，用来查看是否还有文件未提交。</p><h3 id="_1-2-3-add到暂存区" tabindex="-1"><a class="header-anchor" href="#_1-2-3-add到暂存区" aria-hidden="true">#</a> 1.2.3. add到暂存区</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> <span class="token function">add</span> <span class="token string">&#39;click3.py&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注：使用 <code>git add -A</code>或 <code>git add . </code>（<code>.</code>是说本目录下的全部文件）可以提交当前仓库的所有改动。</p><p>对应 <code>git rm --cached xxx</code>取消放入暂存区。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> status


Changes to be committed:
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-4-commit到本地仓库" tabindex="-1"><a class="header-anchor" href="#_1-2-4-commit到本地仓库" aria-hidden="true">#</a> 1.2.4. commit到本地仓库</h3><p>将缓存区里的文件都commit到本地仓库 <code>.git</code>中。</p><p>PS：为什么要提交？这个文件夹里不是有吗？ 本地仓库又名版本库，提交是让Git来管理的意思，在 <code>.git</code>的里面的信息变动。提交后的文件被Git管理起来，对文件的修改、删除，Git都能跟踪，可以比较不同、可以还原。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;备注信息&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+p+'" alt="1664849832160575.png"></p><p>可以使用 <code>git log</code>来查看提交记录。</p><p><img src="'+u+`" alt="16648498324312801.png"></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 补充上一次提交，而不是新开一个提交。</span>
$ <span class="token function">git</span> commit <span class="token parameter variable">-am</span> <span class="token string">&#39;xxx&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-5-删除文件" tabindex="-1"><a class="header-anchor" href="#_1-2-5-删除文件" aria-hidden="true">#</a> 1.2.5. 删除文件</h3><p>如果只是简单地从工作目录中手工删除 <code>rm xxx</code>文件，运行 <code>git status</code> 时就会在 <code>Changes not staged for commit</code>的提示。<strong>因为你没有告诉git你的变动</strong>，git本地仓库中还保留着该文件。</p><ol><li>【删除git本地仓库中，并删除工作区中】</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> <span class="token function">rm</span> xxx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>【删除git本地仓库中没有，只是提交到暂存区的，并删除工作区的】</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> <span class="token function">rm</span> <span class="token parameter variable">-f</span> xxx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>PS：如果git本地仓库中有，也提交到暂存区的。那么删除后，暂存区中的和本地仓库中的都没得。</p><ol start="3"><li>【把文件从暂存区域移除，但仍然希望保留在当前工作目录中：就是取消放入暂存区】</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> <span class="token function">rm</span> <span class="token parameter variable">--cached</span> xxx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>对应的，用 <code>git add xxx</code>再添加到暂存区</p><ol start="4"><li>【暂存区和本地仓库中都没有的：一般是新建在工作区的，才可以直接删除】</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> xxx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_1-3-远程仓库" tabindex="-1"><a class="header-anchor" href="#_1-3-远程仓库" aria-hidden="true">#</a> 1.3. 远程仓库</h2><h3 id="_1-3-1-github-git" tabindex="-1"><a class="header-anchor" href="#_1-3-1-github-git" aria-hidden="true">#</a> 1.3.1. github &amp; git</h3><h4 id="_1-3-1-1-git-config" tabindex="-1"><a class="header-anchor" href="#_1-3-1-1-git-config" aria-hidden="true">#</a> 1.3.1.1. git config</h4><p><code>github</code>，你会有两个关键的信息要填写，一个是你的账号名字，一个是你的邮箱。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> config <span class="token parameter variable">--global</span>  user.name  <span class="token string">&#39;注册的用户名&#39;</span><span class="token punctuation">;</span>
$ <span class="token function">git</span> config <span class="token parameter variable">--global</span>  user.email  <span class="token string">&#39;注册时候的邮箱&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 检查是否配置成功</span>
$ <span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--list</span>
<span class="token assign-left variable">user.name</span><span class="token operator">=</span>Scott Chacon
<span class="token assign-left variable">user.email</span><span class="token operator">=</span>schacon@gmail.com


$ <span class="token function">git</span> config <span class="token parameter variable">--global</span> user.name
Scott Chacon
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-1-2-ssh" tabindex="-1"><a class="header-anchor" href="#_1-3-1-2-ssh" aria-hidden="true">#</a> 1.3.1.2. ssh</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># -C 是表示comment，可有可无</span>
ssh-keygen <span class="token parameter variable">-t</span> rsa <span class="token parameter variable">-C</span> <span class="token string">&#39;your email&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>接着按3个回车就行</p><p><img src="`+g+'" alt="16648498327265737.png"></p><p>在文件夹<code>~/.ssh</code>下，可以看到公钥 <code>id_rsa</code>（私有秘钥）和 <code>id_rsa.pub</code>（公有密钥）。</p><p><img src="'+m+'" alt="16648498330310729.png"></p><p>打开 <code>id_rsa.pub</code>（公有密钥），复制里面的内容。</p><p><img src="'+h+'" alt="16648498334588249.png"></p><p>标题随便起，只是用于区分而已，如同图片中的 <code>Foast</code>。 将复制的公钥内容粘贴在公钥中，确定就ok。</p><h3 id="_1-3-2-将本地写好的东西提交到空的远程仓库" tabindex="-1"><a class="header-anchor" href="#_1-3-2-将本地写好的东西提交到空的远程仓库" aria-hidden="true">#</a> 1.3.2. 将本地写好的东西提交到空的远程仓库</h3><blockquote><p>先在网站创建</p></blockquote><p>git只是个提交工具，将本地仓库的代码提交到远程仓库中。<strong>所以你得先在网站上创建一个远程仓库</strong>，这让git知道提交到哪里。</p><p><img src="'+b+`" alt="16648498338327637.png"></p><p>这个链接就是提交到的远程仓库。</p><blockquote><p>summary</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> init	<span class="token comment"># 在本地写好的东西的文件夹中</span>
<span class="token function">git</span> <span class="token function">add</span> *
<span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&#39;&#39;</span>
<span class="token function">git</span> branch <span class="token parameter variable">-M</span> main
<span class="token function">git</span> remote <span class="token function">add</span> origin git@github.com:USERNAME/REPOSITORY.git
<span class="token function">git</span> push <span class="token parameter variable">-u</span> origin main
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>之后每次就可以直接 <code>git push</code></p><h3 id="_1-3-3-将本地写好的东西提交到有东西的远程仓库" tabindex="-1"><a class="header-anchor" href="#_1-3-3-将本地写好的东西提交到有东西的远程仓库" aria-hidden="true">#</a> 1.3.3. 将本地写好的东西提交到有东西的远程仓库</h3><blockquote><p>git clone</p></blockquote><p>通过HTTPS协议克隆</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone https://gitee.com/xxx.git
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>通过SSH协议克隆</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone git@gitee.com:xxx.git
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>例：不用特地创建一个文件夹了，clone下来默认直接以远程仓库名为名创建一个文件夹。</p><p><img src="`+v+'" alt="166484983399699.png"></p><p><img src="'+f+`" alt="1664849834114752.png"></p><blockquote><p>summary</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone	<span class="token comment"># 先在一个随便的文件夹下</span>
<span class="token punctuation">..</span>.			<span class="token comment"># 进入下好的文件夹下，将本地写好的东西复制到这里</span>
<span class="token function">git</span> <span class="token function">add</span> *
<span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&#39;&#39;</span>
<span class="token function">git</span> push	<span class="token comment"># 已经将远程仓库默认了</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,69);function B(A,C){const n=c("ExternalLinkIcon");return i(),t("div",null,[_,a("p",null,[a("a",x,[l("软件国内源，下得快"),d(n)])]),E])}const $=e(k,[["render",B],["__file","index.html.vue"]]);export{$ as default};
